export function getModelsByCategory(category) {
    return AI_MODELS.filter((m) => m.category === category);
}
export function getFreeModels() {
    return AI_MODELS.filter((m) => m.tier === "free");
}
export function getPaidModels() {
    return AI_MODELS.filter((m) => m.tier === "paid");
}
export function getFreemiumModels() {
    return AI_MODELS.filter((m) => m.tier === "freemium");
}
